import { fileURLToPath, URL } from "node:url";
import tailwindcss from "@tailwindcss/vite";
import { devtools } from "@tanstack/devtools-vite";
import { tanstackStart } from "@tanstack/react-start/plugin/vite";
import viteReact from "@vitejs/plugin-react";
import { nitro } from "nitro/vite";
import { defineConfig } from "vite";
import viteTsConfigPaths from "vite-tsconfig-paths";

const config = defineConfig(() => {
  const isVitest = process.env.VITEST === "true";
  const isDev = process.env.NODE_ENV === "development";
  const enableViteDevtools = isDev && false;
  const devHmrHost = process.env.VITE_DEV_HMR_HOST;
  const devHmrClientPort = process.env.VITE_DEV_HMR_CLIENT_PORT;
  const devHmrProtocol = process.env.VITE_DEV_HMR_PROTOCOL;

  return {
    plugins: [
      ...(enableViteDevtools ? devtools() : []),
      // this is the plugin that enables path aliases
      viteTsConfigPaths({
        projects: ["./tsconfig.json"],
      }),
      tailwindcss(),
      tanstackStart(),
      viteReact(),
      ...(isVitest
        ? []
        : [
            nitro({
              // Work around a nitro-nightly externals bug with packages that
              // contain null branches in `exports` (e.g. msw/interceptors).
              noExternals: true,
            }),
          ]),
    ],
    server: {
      allowedHosts: ["anedot.me", "public.anedot.me", "localhost"],
      cors: true,
      ...(devHmrHost
        ? {
            hmr: {
              clientPort: devHmrClientPort
                ? Number.parseInt(devHmrClientPort, 10)
                : 443,
              host: devHmrHost,
              overlay: true,
              protocol: devHmrProtocol ?? "wss",
              timeout: 60000,
            },
          }
        : {}),
      host: true,
      port: 3210,
      strictPort: true,
      watch: {
        ignored: [
          "*.log",
          ".DS_Store",
          ".claude/**",
          ".git/**",
          ".github/**",
          ".output/**",
          ".tanstack/**",
          ".turbo/**",
          ".vscode/**",
          "dist/**",
          "node_modules/**",
          "playwright-report/**",
          "tests/**",
        ],
      },
    },
    test: {
      environment: "jsdom",
      globals: true,
      setupFiles: ["@workspace/test-utils/vitest"],
      passWithNoTests: true,
      exclude: [
        "**/node_modules/**",
        "**/dist/**",
        "**/.{idea,git,cache,output,temp}/**",
        "**/playwright-report/**",
        "**/test-results/**",
        "tests/integration/**",
        "**/*.spec.*",
      ],
    },
    optimizeDeps: {
      exclude: [
        "msw",
        "@mswjs/interceptors",
        "@tanstack/start-server-core",
        "@tanstack/start-client-core",
        "@tanstack/react-start",
      ],
    },
    resolve: {
      alias: {
        "@": fileURLToPath(new URL("./src", import.meta.url)),
      },
    },
  };
});

export default config;

