import { useSession } from "@tanstack/react-start/server";
import type {
  AuthSessionData,
  AuthTransactionSessionData,
} from "../routes/types/auth";
import { getServerSessionSecret } from "./env";

const sharedCookie = {
  httpOnly: true,
  path: "/",
  sameSite: "lax" as const,
  secure: process.env.NODE_ENV === "production",
};

export async function getAuthSession() {
  return useSession<AuthSessionData>({
    name: "org-next-auth",
    password: getServerSessionSecret(),
    cookie: sharedCookie,
  });
}

export async function getAuthTransactionSession() {
  return useSession<AuthTransactionSessionData>({
    name: "org-next-auth-tx",
    password: getServerSessionSecret(),
    cookie: sharedCookie,
  });
}
