import { createFileRoute, redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";

const loginStartSearchSchema = z.object({
  identity_provider: z.literal("Google").optional(),
  redirect_to: z.string().optional(),
  screen_hint: z.literal("sign_up").optional(),
});

const beginLoginFn = createServerFn({ method: "GET" })
  .inputValidator(loginStartSearchSchema)
  .handler(async ({ data }) => {
    const { beginLoginFlow } = await import("../../server/auth");
    const result = await beginLoginFlow({
      identityProvider: data.identity_provider,
      redirectTo: data.redirect_to,
      screenHint: data.screen_hint,
    });

    throw redirect({ href: result.authorizeUrl });
  });

export const Route = createFileRoute("/oauth/start")({
  validateSearch: loginStartSearchSchema,
  loaderDeps: ({ search }) => search,
  loader: async ({ deps }) => beginLoginFn({ data: deps }),
  component: OAuthStartPage,
});

function OAuthStartPage() {
  return (
    <div className="flex min-h-screen items-center justify-center font-outfit">
      <p className="text-muted-foreground">Redirecting to sign in...</p>
    </div>
  );
}

