import { useEffect } from "react";
import { createFileRoute, useNavigate } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { Loader2 } from "lucide-react";
import { z } from "zod";

const oauthCallbackSearchSchema = z.object({
  code: z.string().optional(),
  error: z.string().optional(),
  error_description: z.string().optional(),
  state: z.string().optional(),
});

const completeLoginCallbackFn = createServerFn({ method: "GET" })
  .inputValidator(oauthCallbackSearchSchema)
  .handler(async ({ data }) => {
    const { completeLoginCallback } = await import("../../server/auth");
    return completeLoginCallback(data);
  });

export const Route = createFileRoute("/oauth/callback")({
  validateSearch: oauthCallbackSearchSchema,
  loaderDeps: ({ search }) => search,
  loader: async ({ deps }) => completeLoginCallbackFn({ data: deps }),
  component: OAuthCallback,
});

function OAuthCallback() {
  const callbackResult = Route.useLoaderData();
  const navigate = useNavigate();

  useEffect(() => {
    if (!callbackResult.ok) {
      return;
    }

    navigate({ to: callbackResult.redirectTo });
  }, [callbackResult, navigate]);

  if (!callbackResult.ok) {
    return (
      <div className="flex min-h-screen items-center justify-center font-outfit">
        <div className="max-w-md rounded-lg border border-destructive/20 bg-destructive/10 p-6 text-center">
          <h1 className="mb-2 font-semibold text-destructive text-lg">
            Sign in failed
          </h1>
          <p className="mb-4 text-destructive/90 text-sm">
            {callbackResult.errorMessage}
          </p>
          <a
            href="/login"
            className="inline-block rounded-md bg-primary px-4 py-2 font-medium text-primary-foreground text-sm hover:bg-primary/90"
          >
            Try again
          </a>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen items-center justify-center font-outfit">
      <div className="text-center">
        <Loader2 className="mx-auto mb-4 h-8 w-8 animate-spin text-primary" />
        <p className="text-muted-foreground">Completing sign in...</p>
      </div>
    </div>
  );
}

