import { createHash, randomBytes, randomUUID } from "node:crypto";
import {
  calculateExpiresAt,
  type LoginStartOptions,
  normalizePostLoginRedirect,
} from "../lib/auth";
import type {
  AuthSessionData,
  AuthTransactionSessionData,
} from "../routes/types/auth";
import {
  clearCurrentAuthSession,
  updateCurrentAuthSession,
} from "./auth-session";
import { getServerAuthConfig } from "./env";
import { getAuthTransactionSession } from "./session";

type TokenResponse = {
  access_token: string;
  expires_in: number;
  id_token: string;
  refresh_token?: string;
};

type OAuthCallbackInput = {
  code?: string;
  error?: string;
  error_description?: string;
  state?: string;
};

type OAuthCallbackResult =
  | {
      errorMessage: string;
      ok: false;
    }
  | {
      ok: true;
      redirectTo: string;
    };

function toBase64Url(buffer: Buffer) {
  return buffer
    .toString("base64")
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=+$/, "");
}

function generatePkcePair() {
  const codeVerifier = toBase64Url(randomBytes(32));
  const codeChallenge = toBase64Url(
    createHash("sha256").update(codeVerifier).digest(),
  );

  return {
    codeChallenge,
    codeVerifier,
    state: randomUUID(),
  };
}

function buildAuthorizeUrl(
  transaction: Required<
    Pick<AuthTransactionSessionData, "codeVerifier" | "state">
  >,
  options: LoginStartOptions,
) {
  const config = getServerAuthConfig();
  const { codeChallenge } = generateChallengeFromVerifier(
    transaction.codeVerifier,
  );

  const params = new URLSearchParams({
    client_id: config.clientId,
    code_challenge: codeChallenge,
    code_challenge_method: "S256",
    redirect_uri: config.redirectUri,
    response_type: "code",
    scope: config.scope,
    state: transaction.state,
  });

  if (options.identityProvider) {
    params.set("identity_provider", options.identityProvider);
  }

  if (options.screenHint) {
    params.set("screen_hint", options.screenHint);
  }

  return `${config.authAppUrl}/authorize?${params.toString()}`;
}

function generateChallengeFromVerifier(codeVerifier: string) {
  return {
    codeChallenge: toBase64Url(
      createHash("sha256").update(codeVerifier).digest(),
    ),
  };
}

async function exchangeCodeForTokens(code: string, codeVerifier: string) {
  const config = getServerAuthConfig();

  const response = await fetch(config.cognitoTokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
    },
    body: new URLSearchParams({
      client_id: config.clientId,
      code,
      code_verifier: codeVerifier,
      grant_type: "authorization_code",
      redirect_uri: config.redirectUri,
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Token exchange failed: ${errorText}`);
  }

  const data: TokenResponse = await response.json();

  return {
    accessToken: data.access_token,
    expiresAt: calculateExpiresAt(data.expires_in),
    idToken: data.id_token,
    refreshToken: data.refresh_token,
  } satisfies AuthSessionData;
}

export async function beginLoginFlow(options: LoginStartOptions = {}) {
  const { codeVerifier, state } = generatePkcePair();
  const txSession = await getAuthTransactionSession();

  await txSession.update({
    codeVerifier,
    redirectTo: normalizePostLoginRedirect(options.redirectTo),
    state,
  });

  return {
    authorizeUrl: buildAuthorizeUrl(
      {
        codeVerifier,
        state,
      },
      options,
    ),
  };
}

export async function completeLoginCallback(
  input: OAuthCallbackInput,
): Promise<OAuthCallbackResult> {
  const txSession = await getAuthTransactionSession();

  if (input.error) {
    await txSession.clear();
    return {
      errorMessage: input.error_description || input.error,
      ok: false,
    };
  }

  if (!input.code) {
    await txSession.clear();
    return {
      errorMessage: "Missing authorization code. Please try signing in again.",
      ok: false,
    };
  }

  if (!txSession.data.state || input.state !== txSession.data.state) {
    await txSession.clear();
    return {
      errorMessage: "Invalid state parameter. Please try signing in again.",
      ok: false,
    };
  }

  if (!txSession.data.codeVerifier) {
    await txSession.clear();
    return {
      errorMessage: "Missing code verifier. Please try signing in again.",
      ok: false,
    };
  }

  try {
    const tokens = await exchangeCodeForTokens(
      input.code,
      txSession.data.codeVerifier,
    );

    if (!tokens.refreshToken) {
      await txSession.clear();
      return {
        errorMessage: "Missing refresh token. Please try signing in again.",
        ok: false,
      };
    }

    await updateCurrentAuthSession(tokens);

    const redirectTo = txSession.data.redirectTo || "/organizations";
    await txSession.clear();

    return {
      ok: true,
      redirectTo,
    };
  } catch (error) {
    await txSession.clear();

    return {
      errorMessage:
        error instanceof Error ? error.message : "Token exchange failed.",
      ok: false,
    };
  }
}

export async function beginLogoutFlow() {
  const config = getServerAuthConfig();
  const txSession = await getAuthTransactionSession();

  await Promise.all([clearCurrentAuthSession(), txSession.clear()]);

  const logoutUrl = new URL("/logout", config.authAppUrl);
  logoutUrl.searchParams.set("client_id", config.clientId);
  logoutUrl.searchParams.set("logout_uri", config.logoutUri);

  return {
    logoutUrl: logoutUrl.toString(),
  };
}

