import {
  ORG_NEXT_APP_BOOTSTRAP_USER_ID,
  type OrgNextAppBootstrap,
  type OrgNextTenant,
  type OrgNextTenantMembership,
  type OrgNextUser,
} from "@workspace/api-client/org-next";
import { getOrgApiJson, OrgApiError } from "./org-api";
import { resolveOrgApiAccessToken } from "./org-api-access-token";

const pickCurrentTenant = (
  accessibleTenants: OrgNextTenant[],
  tenantId?: number,
) => {
  if (tenantId === undefined) {
    return accessibleTenants[0] ?? null;
  }

  return accessibleTenants.find((tenant) => tenant.id === tenantId) ?? null;
};

const buildAppBootstrap = ({
  accessibleTenants,
  membershipsForUser,
  tenantId,
  user,
}: {
  accessibleTenants: OrgNextTenant[];
  membershipsForUser: OrgNextTenantMembership[];
  tenantId?: number;
  user: OrgNextUser;
}): OrgNextAppBootstrap => {
  const currentTenant = pickCurrentTenant(accessibleTenants, tenantId);
  const currentMembership = currentTenant
    ? (membershipsForUser.find(
        (membership) => membership.tenant_id === currentTenant.id,
      ) ?? null)
    : (membershipsForUser[0] ?? null);

  return {
    accessibleTenants,
    currentMembership,
    currentTenant,
    currentUser: user,
    memberships: membershipsForUser,
    tenant: currentTenant,
    tenants: accessibleTenants,
    user,
    users: [user],
  };
};

async function fetchMembershipsForUser({
  accessToken,
  userId,
}: {
  accessToken: string;
  userId: number;
}): Promise<OrgNextTenantMembership[]> {
  const path = `/tenant_memberships?user_id=${userId}`;

  try {
    return await getOrgApiJson<OrgNextTenantMembership[]>(path, {
      accessToken,
    });
  } catch (error) {
    if (error instanceof OrgApiError && error.status === 401) {
      throw error;
    }

    return [];
  }
}

async function fetchTenantsForMemberships({
  accessToken,
  memberships,
}: {
  accessToken: string;
  memberships: OrgNextTenantMembership[];
}): Promise<OrgNextTenant[]> {
  const tenants: OrgNextTenant[] = [];

  for (const membership of memberships) {
    try {
      const tenant = await getOrgApiJson<OrgNextTenant>(
        `/tenants/${membership.tenant_id}`,
        { accessToken },
      );
      tenants.push(tenant);
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw error;
      }
    }
  }

  return tenants;
}

export async function getAppBootstrapData({
  tenantId,
}: {
  tenantId?: number;
} = {}): Promise<OrgNextAppBootstrap | null> {
  const accessToken = await resolveOrgApiAccessToken();

  if (accessToken === null) {
    return null;
  }

  const userId = ORG_NEXT_APP_BOOTSTRAP_USER_ID;

  let user: OrgNextUser;

  try {
    user = await getOrgApiJson<OrgNextUser>(`/users/${userId}`, {
      accessToken,
    });
  } catch (error) {
    if (error instanceof OrgApiError && error.status === 404) {
      return null;
    }

    throw error;
  }

  const membershipsForUser = await fetchMembershipsForUser({
    accessToken,
    userId,
  });

  const accessibleTenants = await fetchTenantsForMemberships({
    accessToken,
    memberships: membershipsForUser,
  });

  return buildAppBootstrap({
    accessibleTenants,
    membershipsForUser,
    tenantId,
    user,
  });
}

