import { createFileRoute, redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { Loader2 } from "lucide-react";

const beginLogoutFn = createServerFn({ method: "GET" }).handler(async () => {
  const { beginLogoutFlow } = await import("../server/auth");
  const result = await beginLogoutFlow();

  throw redirect({ href: result.logoutUrl });
});

export const Route = createFileRoute("/logout")({
  loader: () => beginLogoutFn(),
  component: LogoutPage,
});

function LogoutPage() {
  return (
    <div className="flex min-h-screen items-center justify-center font-outfit">
      <div className="text-center">
        <Loader2 className="mx-auto mb-4 h-8 w-8 animate-spin text-primary" />
        <p className="text-muted-foreground">Signing out...</p>
      </div>
    </div>
  );
}

