import { AppHeader } from "@/components/app-header";
import {
  createFileRoute,
  getRouteApi,
  Link,
  redirect,
} from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { Badge, Button, Card, Progress } from "@workspace/ui";
import {
  ArrowRight,
  Check,
  ChevronRight,
  Copy,
  Plus,
  Settings,
  Target,
} from "lucide-react";

// Get the parent data
const authedRouteApi = getRouteApi("/_authed");

const getDashboardPageDataFn = createServerFn({ method: "GET" }).handler(
  async () => {
    const { getDashboardPageData } = await import("../../server/dashboard");
    const { OrgApiError } = await import("../../server/org-api");

    try {
      const data = await getDashboardPageData();

      if (!data) {
        throw redirect({ to: "/login" });
      }

      return data;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  },
);

