import { isOrgNextBypassAuth } from "@/lib/org-next-flags";
import { readAuthenticatedAccessToken } from "./auth-session";

/**
 * Session token when logged in; otherwise a dev-only token when
 * `VITE_ORG_NEXT_BYPASS_AUTH=true` (local backend may ignore auth).
 */
export async function resolveOrgApiAccessToken(): Promise<string | null> {
  const fromSession = await readAuthenticatedAccessToken();
  if (fromSession) {
    return fromSession;
  }

  if (isOrgNextBypassAuth()) {
    const dev = import.meta.env.VITE_ORG_NEXT_DEV_ACCESS_TOKEN;
    return typeof dev === "string" ? dev : "";
  }

  return null;
}
